head.script:
scwin.pos_groupCode = 0;
scwin.pos_crn = 0;
scwin.g_sUserId = "";
scwin.gJudgeYn = "0";

scwin.onpageload = async function() {
    scwin.g_sUserId = $c.ses.getUserId();
    scwin.gJudgeYn = "0";
    scwin.f_Reset();
    ica_confYr.setFocus();
    scwin.f_retrieveJudge();
};

scwin.onUdcCompleted = function() {
    ed_crn.setFocus();
};

scwin.f_openPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {
    let rtnList = [];
    let cd = "";
    let nm = "";
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }
    switch (select_code) {
        case '3':
            rtnList = $c.gus.cfCommonPopUp('retrieveCreditCrnInfo', cd, nm, "T", null, null, null, null, null, null, null, null, null);
            scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
            break;
        default:
            await $c.gus.cfAlertMsg("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    }
};

scwin.f_CheckPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }
    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            await scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.hidVal = "";
    }
};

scwin.f_resultPopUp = function(orgObjCd, orgObjNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        orgObjCd.setValue(rtnList[0]);
        orgObjNm.setValue(rtnList[1]);
        orgObjCd.hidVal = rtnList[0];
        orgObjNm.hidVal = rtnList[1];
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.hidVal = "";
        orgObjNm.hidVal = "";
    }
};

scwin.f_checkCommonPopUp = async function(select_code, pCode, pName, Row) {
    let code = ds_ConfidenceInfo.getCellData(Row, pCode);
    if (code.trim() != "") {
        await scwin.f_openCommonPopUp(select_code, pCode, pName, Row, "T");
    } else {
        ds_ConfidenceInfo.setCellData(Row, pCode, "");
        ds_ConfidenceInfo.setCellData(Row, pName, "");
    }
};

scwin.f_openCommonPopUp = async function(select_code, pCode, pName, Row, pClose) {
    let rtnList = null;
    let code = ds_ConfidenceInfo.getCellData(Row, pCode);
    if (code == null || code == "") {
        code = "";
    }
    let sCmdName = "";
    switch (select_code) {
        case '2':
            sCmdName = "retrieveCreditCrnInfo";
            rtnList = $c.gus.cfCommonPopUp(sCmdName, code, "", pClose, null, null, null, null, null, null, null, null, null, null, null, null, null);
            break;
    }
    $c.gus.cfSetGridReturnValue(rtnList, ds_ConfidenceInfo, Row, pCode, pName);
};

scwin.f_retrieveJudge = async function() {
    await $c.sbm.execute(sbm_retrieveJudge);
};

scwin.sbm_retrieveJudge_submitdone = async function(e) {
    for (let i = 0; i < ds_judge.getRowCount(); i++) {
        if (scwin.g_sUserId == ds_judge.getCellData(i, "col1")) {
            scwin.gJudgeYn = "1";
        }
    }
    if (scwin.gJudgeYn == "1") {
        $c.gus.cfEnableObjects([btn_set]);
    } else {
        $c.gus.cfDisableObjects([btn_set]);
    }
};

scwin.sbm_retrieveJudge_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_Initial = function() {
    $c.gus.cfDisableKey();
};

scwin.f_Reset = function() {
    scwin.f_Initial();
};

scwin.f_Retrieve = async function() {
    if (ed_crn.getValue().trim() == "" && ed_crnNm.getValue().trim() == "") {
        let chk = await $c.gus.cfValidate([ed_crnNm]);
        if (!chk) {
            return;
        }
    }
    await $c.sbm.execute(sbm_searchConfidenceInfo);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.sbm_searchConfidenceInfo_submitdone = async function(e) {
    spa_totalRow.setValue(ds_ConfidenceInfo.getTotalRow());
    $c.gus.cfGoPrevPosition(ds_ConfidenceInfo, scwin.pos_groupCode);
    if (ds_ConfidenceInfo.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.sbm_searchConfidenceInfo_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_AddRow = function() {
    ds_ConfidenceInfo.insertRow();
    spa_totalRow.setValue(ds_ConfidenceInfo.getTotalRow());
};

scwin.f_delMarked = function() {
    for (let i = ds_ConfidenceInfo.getRowCount() - 1; i >= 0; i--) {
        if (ds_ConfidenceInfo.getCellData(i, "num") == "T") {
            ds_ConfidenceInfo.removeRow(i);
        }
    }
    spa_totalRow.setValue(ds_ConfidenceInfo.getTotalRow());
};

scwin.f_Undo = function() {
    ds_ConfidenceInfo.undoAll();
};

scwin.f_Save = async function() {
    if (!ds_ConfidenceInfo.isUpdated()) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }
    let chkValid = await $c.gus.cfValidate([gr_ConfidenceInfo]);
    if (!chkValid) {
        return;
    }
    let chkConfirm = await $c.win.confirm("저장하시겠습니까?");
    if (chkConfirm) {
        scwin.pos_crn = ds_ConfidenceInfo.getRowPosition();
        await $c.sbm.execute(sbm_ConfidenceInfo);
    }
};

scwin.sbm_ConfidenceInfo_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.sbm_ConfidenceInfo_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_Excel = async function() {
    let chk = await $c.win.confirm("Excel로 다운로드 하시겠습니까?");
    if (chk) {
        $c.data.downloadGridViewExcel(gr_ConfidenceInfo, {"fileName": "신용정보조회.xlsx", "sheetName": "신용정보"});
    }
};

scwin.f_CheckFileExt = function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext == path.substring((flen - elen), flen));
};

scwin.f_Import = async function() {
    ds_excel.removeAll();
    ds_temp.removeAll();
    // TODO: GAUCE InputFile(inputF.Open()) 기반 CSV 업로드는 WebSquare 엑셀 업로드 UDC로 대체 필요
    await $c.gus.cfAlertMsg("CSV 업로드 기능은 WebSquare 엑셀 업로드 기능으로 대체 필요합니다.");
};

scwin.f_AddRowUploaded = function() {
    if (ds_temp.getRowCount() > 0) {
        ds_ConfidenceInfo.removeAll();
        for (let i = 0; i < ds_temp.getRowCount(); i++) {
            ds_ConfidenceInfo.insertRow();
            let row = ds_ConfidenceInfo.getRowCount() - 1;
            ds_ConfidenceInfo.setCellData(row, "confYr", ds_temp.getCellData(i, "confYr"));
            ds_ConfidenceInfo.setCellData(row, "crn", ds_temp.getCellData(i, "crn"));
            ds_ConfidenceInfo.setCellData(row, "confGrd", ds_temp.getCellData(i, "confGrd"));
            ds_ConfidenceInfo.setCellData(row, "liablRt", ds_temp.getCellData(i, "liablRt"));
            ds_ConfidenceInfo.setCellData(row, "sellAmtIncrRt", ds_temp.getCellData(i, "sellAmtIncrRt"));
            ds_ConfidenceInfo.setCellData(row, "flowRt", ds_temp.getCellData(i, "flowRt"));
            ds_ConfidenceInfo.setCellData(row, "sellAmtMwoundMarginRt", ds_temp.getCellData(i, "sellAmtMwoundMarginRt"));
            ds_ConfidenceInfo.setCellData(row, "totSellAmt", ds_temp.getCellData(i, "totSellAmt"));
            ds_ConfidenceInfo.setCellData(row, "aset", ds_temp.getCellData(i, "aset"));
            ds_ConfidenceInfo.setCellData(row, "capi", ds_temp.getCellData(i, "capi"));
            ds_ConfidenceInfo.setCellData(row, "bizStDd", ds_temp.getCellData(i, "bizStDd"));
            ds_ConfidenceInfo.setCellData(row, "entrScal", ds_temp.getCellData(i, "entrScal"));
            ds_ConfidenceInfo.setCellData(row, "staffCnt", ds_temp.getCellData(i, "staffCnt"));
            ds_ConfidenceInfo.setCellData(row, "closureQuitYn", ds_temp.getCellData(i, "closureQuitYn"));
        }
    }
    spa_totalRow.setValue(ds_ConfidenceInfo.getTotalRow());
    return true;
};

scwin.f_Create = async function() {
    if (ica_confYr.getValue().trim() == "") {
        let chk = await $c.gus.cfValidate([ica_confYr]);
        if (!chk) {
            return;
        }
    }
    let chkConfirm = await $c.win.confirm("일괄한도를 설정하시겠습니까?");
    if (!chkConfirm) {
        return false;
    }
    await $c.sbm.execute(sbm_createCreditLimit);
};

scwin.sbm_createCreditLimit_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

scwin.sbm_createCreditLimit_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.gr_ConfidenceInfo_onheaderclick = function(headerIndex, columnIndex, columnId) {
    if (columnId == "num") {
        let bCheck = gr_ConfidenceInfo.getHeaderValue(headerIndex, columnIndex);
        if (bCheck == "T" || bCheck == true) {
            for (let i = 0; i < ds_ConfidenceInfo.getRowCount(); i++) {
                ds_ConfidenceInfo.setCellData(i, "num", "T");
            }
        } else {
            for (let i = 0; i < ds_ConfidenceInfo.getRowCount(); i++) {
                ds_ConfidenceInfo.setCellData(i, "num", "F");
            }
        }
    }
};

scwin.gr_ConfidenceInfo_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "crn") {
        scwin.f_openCommonPopUp('2', "crn", "crnNm", rowIndex, 'F');
    }
};

scwin.gr_ConfidenceInfo_oneditend = function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (columnId == 'crn') {
        scwin.f_checkCommonPopUp('2', "crn", "crnNm", rowIndex);
    }
};

scwin.btn_Add_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_set_onclick = function(e) {
    scwin.f_Create();
};

scwin.f_addRow = function() {
    scwin.f_AddRow();
};

scwin.f_deleteRow = function() {
    scwin.f_delMarked();
};

scwin.f_cancelRow = function() {
    scwin.f_Undo();
};
